+describe('reqContext', () => {
+  test('passes req as Joi context during validation', async () => {
+    expect.assertions(2);
+    const server = Server();
+    const team = new Teamwork({ meetings: 2 });
+
+    server.post('/:userId', celebrate({
+      body: {
+        id: Joi.number().only(Joi.ref('$params.userId')),
+      },
+      params: {
+        userId: Joi.number().integer().required(),
+      },
+    }, null, {
+      reqContext: true,
+    }), (req, res) => {
+      team.attend(req);
+      res.send();
     });
+
+    server.inject({
+      method: 'POST',
+      url: '/12345',
+      payload: {
+        id: 12345,
+      },
+    }, team.attend.bind(team));
+
+    const [req, res] = await team.work;
+    expect(req.body.id).toEqual(req.params.userId);
+    expect(res.statusCode).toBe(200);
+  });
+
+  test('fails validation based on req values', async () => {
+    expect.assertions(2);
+    const server = Server();
+    const team = new Teamwork();
+    const next = jest.fn();
+
+    server.post('/:userId', celebrate({
+      body: {
+        id: Joi.number().only(Joi.ref('$params.userId')),
+      },
+      params: {
+        userId: Joi.number().integer().required(),
+      },
+    }, null, {
+      reqContext: true,
+    }), next);
+
+    server.inject({
+      method: 'POST',
+      url: '/123',
+      payload: {
+        id: 12345,
+      },
+    }, team.attend.bind(team));
+
+    const res = await team.work;
+
+    expect(res.statusCode).toBe(500);
+    expect(next).not.toHaveBeenCalled();
   });
 });

